```js
app.get('/utenti/:id', (request, response) => {
    const id = Number(request.params.id);
    const utente = utenti.find(u => u.id === id);
    if (!utente) {
        return response.status(404).json({ errore: 'Utente non trovato' });
    }
    response.json(utente);
});
```
